#!/usr/bin/env bun
/**
 * Read docs/WHITEPAPER.md, parse with marked, emit a TS module that
 * the /whitepaper route imports at compile time. Keeping the parse
 * at build time means marked stays in devDependencies and never
 * ships in the Cloudflare Worker bundle.
 *
 * Wired into apps/platform's `build` script. The generated file is
 * gitignored — `bun run build` regenerates it from the markdown
 * source on every CI/prod build, so the .md is the single source of
 * truth.
 */
import { readFileSync, writeFileSync, mkdirSync, statSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { marked } from 'marked';

const HERE = dirname(new URL(import.meta.url).pathname);
const SOURCE = resolve(HERE, '../../../docs/WHITEPAPER.md');
const OUTPUT = resolve(HERE, '../src/lib/_generated/whitepaper.ts');

const md = readFileSync(SOURCE, 'utf-8');

// The .md sits in docs/, so its relative links assume a docs-folder
// context (./CURRENT_STATE.md, ./superpowers/plans/...). When served
// at /whitepaper they 404 — rewrite them to point at the GitHub
// rendering of the same files so users can follow them.
const GH_DOCS_BASE = 'https://github.com/theprovider123/shippie/blob/main/docs/';
const rewritten = md.replace(/\]\(\.\/([^)]+)\)/g, (_, path) => `](${GH_DOCS_BASE}${path})`);

const html = marked.parse(rewritten, { gfm: true, breaks: false });
const lastUpdated = statSync(SOURCE).mtime.toISOString().slice(0, 10);

mkdirSync(dirname(OUTPUT), { recursive: true });

const escaped = JSON.stringify(html);
writeFileSync(
  OUTPUT,
  `// Generated by scripts/prepare-whitepaper.mjs from docs/WHITEPAPER.md.\n// Do not edit by hand — re-run \`bun scripts/prepare-whitepaper.mjs\`.\n\nexport const html: string = ${escaped};\nexport const lastUpdated: string = ${JSON.stringify(lastUpdated)};\n`,
);

console.log(`[prepare-whitepaper] wrote ${OUTPUT} (${html.length} bytes, last-updated ${lastUpdated})`);
